                    duration: CHAR_DURATION,
                    delay: i * CHAR_STAGGER,
                    ease: CHAR_EASE,
                  }}
                >
                  {char === " " ? " " : char}
                </m.span>
              ))}
            </m.h1>
          )}

          {scene === 2 && (
            <m.h1
              key="scene-2"
