input.new_string:
// Programmatic Audio sidesteps the `<audio>` caption-track lint rule and
// lets us preload the cue without rendering hidden media. Audio starts at
// scene 1 (with the "Welcome to GAIA" reveal) and is deliberately NOT
// paused on unmount so the piano can ring out into the onboarding scene.
//
// Autoplay strategy:
//   1. Try `play()` immediately — this rides the gesture activation from
//      the click that triggered the route push into /onboarding (valid for
//      ~5s on a client-side navigation).
//   2. If the browser rejects (hard reload, direct URL, no recent gesture),
//      register a one-shot listener so the audio fires on the user's very
//      next interaction — pointer move, click, key press, touch, scroll.
useEffect(() => {
  const audio = new Audio("/audio/onboarding-intro.mp3");
  audio.preload = "auto";
  audio.volume = 0.7;
  audioRef.current = audio;

  let cleanupListeners: (() => void) | null = null;

  const attemptPlay = () => audio.play();

  const armFallback = () => {
    const events = [
      "pointerdown",
      "pointermove",
      "click",
      "keydown",
      "touchstart",
      "scroll",
    ] as const;
    const handler = () => {
      audio.play().catch(() => {});
      cleanupListeners?.();
      cleanupListeners = null;
    };
    for (const evt of events) {
      window.addEventListener(evt, handler, {
        once: true,
        passive: true,
        capture: true,
      });
    }
    cleanupListeners = () => {
      for (const evt of events) {
        window.removeEventListener(evt, handler, { capture: true });
      }
    };
  };

  attemptPlay().catch(armFallback);

  return () => {
    cleanupListeners?.();
    audioRef.current = null;
  };
}, []);

