    "pointermove",
    "click",
    "keydown",
    "touchstart",
    "scroll",
  ] as const;
  let played = false;
  const tryPlay = () => {
    if (played) return;
    played = true;
    audio.play().catch(() => {
      played = false;
    });
    removeListeners();
  };
  const handler = () => tryPlay();
  const removeListeners = () => {
    for (const evt of events) {
      window.removeEventListener(evt, handler, { capture: true });
