  };
  for (const evt of events) {
    window.addEventListener(evt, handler, {
      passive: true,
      capture: true,
    });
  }

  // Attempt immediate playback (rides the navigation gesture window).
  tryPlay();

  return () => {
    removeListeners();
    audioRef.current = null;
  };
}, []);

