/**
 * Top-level orchestrator page for the onboarding flow. Uses `useOnboarding`
 * to get the derived stage, then picks a `stageContent` and a `composer`
 * for that stage. Stage-driven swapping keeps each stage's logic isolated;
 * shared transcript + progress chrome live in `OnboardingShell` /
 * `MessagesRegion`. `skipAutoRedirect` keeps the chat stage rendered here
 * instead of redirecting into the standalone `/c/:id` route.
 */

"use client";

import { AnimatePresence } from "motion/react";
import * as m from "motion/react-m";
import { useState } from "react";
import { MessagesRegion } from "@/features/onboarding/components/MessagesRegion";
import { OnboardingIntro } from "@/features/onboarding/components/OnboardingIntro";
import { OnboardingShell } from "@/features/onboarding/components/OnboardingShell";
import {
  Chat,
  ChatComposer,
  FocusComposer,
  Platforms,
  ProcessingComposer,
  QuestionsComposer,
  RevealTodos,
  RevealWritingStyle,
  RevealWritingStyleComposer,
  useChatStage,
  Workflows,
  WorkflowsComposer,
} from "@/features/onboarding/components/stages";
import { EASE_OUT_QUART } from "@/features/onboarding/constants/motion";
import { useOnboarding } from "@/features/onboarding/hooks/useOnboarding";

const INTRO_FADE_IN = {
  initial: { opacity: 0, filter: "blur(12px)" },
  animate: { opacity: 1, filter: "blur(0px)" },
  transition: { duration: 0.6, ease: EASE_OUT_QUART },
} as const;

const INTRO_SEEN_KEY = "gaia.onboarding.introSeen";

function hasSeenIntro(): boolean {
  if (typeof window === "undefined") return false;
  try {
    return window.sessionStorage.getItem(INTRO_SEEN_KEY) === "1";
  } catch {
    return false;
  }
}

function markIntroSeen(): void {
  try {
    window.sessionStorage.setItem(INTRO_SEEN_KEY, "1");
  } catch {
    // sessionStorage unavailable (private mode, etc.) — silently skip.
  }
}

export default function Onboarding() {
  const { state, stage, dispatch, restart } = useOnboarding({
    skipAutoRedirect: true,
  });
  const [introDone, setIntroDone] = useState<boolean>(hasSeenIntro);

  const handleRestart = () => {
    try {
      window.sessionStorage.removeItem(INTRO_SEEN_KEY);
    } catch {}
    setIntroDone(false);
    return restart();
  };

  const handleIntroComplete = () => {
    markIntroSeen();
    setIntroDone(true);
  };

  const chat = useChatStage(state, dispatch);

  const stageContent = (() => {
    switch (stage) {
      case "questions":
      case "focus":
      case "processing":
        return null;
      case "revealWriting":
        return <RevealWritingStyle state={state} />;
      case "revealTodos":
        return <RevealTodos state={state} dispatch={dispatch} />;
      case "workflows":
        return <Workflows state={state} dispatch={dispatch} />;
      case "platforms":
        return <Platforms state={state} dispatch={dispatch} />;
      case "chat":
        return <Chat state={state} chat={chat} />;
    }
  })();

  const composer = (() => {
    switch (stage) {
      case "questions":
        return <QuestionsComposer state={state} dispatch={dispatch} />;
      case "focus":
        return <FocusComposer state={state} dispatch={dispatch} />;
      case "processing":
        return <ProcessingComposer state={state} dispatch={dispatch} />;
      case "revealWriting":
        return <RevealWritingStyleComposer state={state} dispatch={dispatch} />;
      case "revealTodos":
        return null;
      case "workflows":
        return <WorkflowsComposer state={state} dispatch={dispatch} />;
      case "platforms":
        return null;
      case "chat":
        return <ChatComposer chat={chat} />;
    }
  })();

  const wrappedComposer = introDone ? (
    <m.div {...INTRO_FADE_IN}>{composer}</m.div>
  ) : null;

  return (
    <>
      <OnboardingShell
        state={state}
        stage={stage}
        onRestart={handleRestart}
        composer={wrappedComposer}
      >
        {introDone ? (
          <m.div {...INTRO_FADE_IN}>
            <MessagesRegion state={state} stage={stage} />
            {stageContent}
          </m.div>
        ) : null}
      </OnboardingShell>
      <AnimatePresence>
        {!introDone && (
          <OnboardingIntro onComplete={() => setIntroDone(true)} />
        )}
      </AnimatePresence>
    </>
  );
}

